// Get data from previous nodes
const webhook = $('Webhook').first().json;
const survey = $('Supabase - Fetch Survey').first().json;

// Extract data
const { responseId, tenant_id, answers } = webhook;
const { title: surveyTitle, questions } = survey;

// Build Q&A pairs for AI context
const qaContext = questions
  .sort((a, b) => a.order - b.order)
  .map(q => {
    const answer = answers[q.id];

    // Format answer based on type
    let formattedAnswer;
    if (Array.isArray(answer)) {
      formattedAnswer = answer.join(', ');
    } else if (answer === undefined || answer === null) {
      formattedAnswer = '(brak odpowiedzi)';
    } else {
      formattedAnswer = String(answer);
    }

    return {
      question: q.question,
      type: q.type,
      answer: formattedAnswer,
      required: q.required
    };
  });

// Build AI prompt
const prompt = `
Przeanalizuj poniższe zgłoszenie klienta i oceń jego kwalifikację do konsultacji prawnej.

TYTUŁ FORMULARZA: ${surveyTitle}

ODPOWIEDZI KLIENTA:
${qaContext.map((qa, i) => `${i + 1}. ${qa.question}\n   Odpowiedź: ${qa.answer}`).join('\n\n')}

ZADANIE:
Oceń to zgłoszenie pod kątem:
1. **Pilność sprawy** - czy wymaga natychmiastowej reakcji (0-10)
2. **Złożoność** - jak skomplikowana jest sprawa (0-10)
3. **Wartość sprawy** - potencjalna wartość ekonomiczna dla kancelarii (0-10)
4. **Prawdopodobieństwo sukcesu** - czy sprawa ma solidne podstawy (0-10)
5. **Krótkie podsumowanie** - 1-2 zdania o sprawie
6. **Rekomendacja** - czy warto umówić konsultację (QUALIFIED / DISQUALIFIED / NEEDS_MORE_INFO)
7. **Uwagi dla prawnika** - maksymalnie 3 kluczowe punkty do omówienia na spotkaniu

Odpowiedź TYLKO w formacie JSON:
{
  "urgency_score": 0-10,
  "complexity_score": 0-10,
  "value_score": 0-10,
  "success_probability": 0-10,
  "summary": "krótkie podsumowanie",
  "recommendation": "QUALIFIED | DISQUALIFIED | NEEDS_MORE_INFO",
  "notes_for_lawyer": ["punkt 1", "punkt 2", "punkt 3"]
}
`.trim();

// Return structured data for AI node
return {
  responseId,
  tenant_id,
  surveyTitle,
  prompt,
  metadata: {
    totalQuestions: questions.length,
    answeredQuestions: qaContext.filter(qa => qa.answer !== '(brak odpowiedzi)').length
  }
};

